+    #[test]
+    fn very_high_max_change_allows_immediate_convergence() {
+        // With max_change_per_tick = 1.0 (100%), one tick should fully converge
+        let config = AutoTuneConfig {
+            hysteresis_ticks: 1,
+            max_change_per_tick: 1.0,
+            ..default_config()
+        };
+        let tuner = AutoTuner::new(config);
+
